```
#include <string>
#include <regex>

std::string markdown_to_html(const std::string& markdown) {
    // Define regular expressions for finding markdown formatting
    std::regex italic_regex("\\*([^\\*]+)\\*");
    std::regex bold_regex("\\*\\*([^\\*]+)\\*\\*");
    std::regex link_regex("\\[([^\\[]+)\\]\\((https?://[^\\)]+)\\)");

    // Create a stringstream to build the HTML output
    std::stringstream html_output;

    // Find and replace markdown formatting with HTML formatting
    std::smatch match;
    while (std::regex_search(markdown.cbegin(), markdown.cend(), match, italic_regex)) {
        html_output << "<i>" << match[1] << "</i>";
    }
    while (std::regex_search(markdown.cbegin(), markdown.cend(), match, bold_regex)) {
        html_output << "<b>" << match[1] << "</b>";
    }
    while (std::regex_search(markdown.cbegin(), markdown.cend(), match, link_regex)) {
        html_output << "<a href=\"" << match[2] << "\" target=\"_blank\">" << match[1] << "</a>";
    }

    // Remove any remaining markdown formatting
    std::regex remaining_regex("\\*|\\[|\\]");
    html_output << std::regex_replace(markdown, remaining_regex, "");

    return html_output.str();
}
```
This function uses regular expressions to find and replace markdown formatting (italics, bold, and links) with HTML formatting, and then removes any remaining markdown formatting.

Note that this function is just an example and may not handle all possible cases of markdown formatting. Depending on the specific requirements of your use case, you may need to add additional regular expressions or adjust the existing ones to handle all desired cases.

