function checkPrimeNumbers(numbers) {
  for (let i = 0; i < numbers.length; i++) {
    const number = numbers[i];
    let isPrime = true;

    if (number <= 1) {
      isPrime = false;
    } else if (number === 2) {
      isPrime = true;
    } else {
      for (let j = 2; j <= Math.sqrt(number); j++) {
        if (number % j === 0) {
          isPrime = false;
          break;
        }
      }
    }

